// Caso: Formatear segundos a hh:mm:ss | Nivel: Básico | Categoría: Utilidades

function pad2(n){ return String(n).padStart(2,'0'); }
function solve(totalSeconds){
  const s = Math.max(0, Math.floor(totalSeconds));
  const h = Math.floor(s / 3600);
  const m = Math.floor((s % 3600) / 60);
  const sec = s % 60;
  return `${pad2(h)}:${pad2(m)}:${pad2(sec)}`;
}

snippets.C0014:
// Svelte (Framework UI) · 5.0.0
// Ubicación sugerida: App.svelte
// Caso: Validar paréntesis/corchetes/llaves | Nivel: Intermedio | Categoría: Stacks

function solve(s) {
  const st = [];
  const pairs = { ')':'(', ']':'[', '}':'{' };
  for (const ch of s) {
    if (ch==='('||ch==='['||ch==='{') st.push(ch);
    else if (ch===')'||ch===']'||ch==='}') {
      if (st.pop() !== pairs[ch]) return false;
    }
  }
  return st.length === 0;
}

