// Svelte (Framework UI) · 5.0.0
// Ubicación sugerida: App.svelte
// C0661 · Retry + backoff + timeout (Intermedio, Resiliencia)
// Browser: retry con backoff manual
async function solve(fn, retries = 5) {
  let delay = 200;
  for (let i=0; i<=retries; i++) {
    try { return await fn(); } catch (e) {
      if (i === retries) throw e;
      const jitter = Math.floor(Math.random() * 100);
      await new Promise(r => setTimeout(r, delay + jitter));
      delay = Math.min(delay * 2, 5000);
    }
  }
}

